import { useEffect, useMemo, useState } from 'react';
import { useVoucherInitData } from './useVoucherInitData';
import { resolveProcessingLevelSelectOptions } from '../utils/voucherProcessingLevelOptions';

/** Mức xử lý từ init-data — Pattern D · `defaultProcessingLevel` từ BE. */
export function useSalesFormProcessingLevel(formName: string) {
  const { processingLevelOptions, defaultProcessingLevel, loading } = useVoucherInitData(formName);
  const [processingLevel, setProcessingLevel] = useState('');

  const processingLevelSelectOptions = useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (cancelled || processingLevel) return;
      const defaultLevel = defaultProcessingLevel
        ?? (processingLevelOptions[0] ? String(processingLevelOptions[0].value) : '');
      if (!defaultLevel) return;
      setProcessingLevel(defaultLevel);
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [processingLevel, defaultProcessingLevel, processingLevelOptions]);

  return {
    processingLevel,
    setProcessingLevel,
    processingLevelOptions: processingLevelSelectOptions,
    defaultProcessingLevel,
    loading,
  };
}
