import React from 'react';
import { MoneyInput, NumberInput } from '@linm-soft/common-components';
import type { InvoiceLineDto } from '../../services/bh/models';
import {
  clampLineDiscountAmount,
  clampLineDiscountRate,
  lineGrossAmount,
} from '../../utils/orderLines';
import df from '../../styles/documentForm.module.css';

export type InvoiceLineDiscountPairProps = {
  line: InvoiceLineDto;
  lineIndex: number;
  canEdit: boolean;
  onDiscountRateChange: (rate: number) => void;
  onDiscountAmountChange: (amount: number) => void;
};

export const InvoiceLineDiscountPair: React.FC<InvoiceLineDiscountPairProps> = ({
  line,
  lineIndex,
  canEdit,
  onDiscountRateChange,
  onDiscountAmountChange,
}) => {
  const gross = lineGrossAmount(line);
  const rate = clampLineDiscountRate(line.discountRate ?? 0);
  const amount = clampLineDiscountAmount(line.discountAmount ?? 0, gross);
  const rateActive = rate > 0;
  const amountActive = !rateActive && amount > 0;

  return (
    <div className={df.lineDiscountPair} data-testid={`line-${lineIndex + 1}-discount-pair`}>
      <NumberInput
        value={rate}
        onChange={nextRate => onDiscountRateChange(clampLineDiscountRate(nextRate))}
        disabled={!canEdit || amountActive}
        format={{ maxDecimals: 2, thousandSeparator: ' ', decimalSeparator: ',' }}
        aria-label="% giảm giá dòng"
        data-testid={`line-${lineIndex + 1}-discountRate`}
      />
      <MoneyInput
        value={amount}
        onChange={nextAmount => onDiscountAmountChange(clampLineDiscountAmount(nextAmount, gross))}
        disabled={!canEdit || rateActive}
        aria-label="Tiền giảm giá dòng"
        data-testid={`line-${lineIndex + 1}-discountAmount`}
      />
    </div>
  );
};
